    if (raw === undefined || raw === null || raw === '') return 1;
    const n = Number(raw);
    return isNaN(n) ? 1 : n;
}

salesLines.forEach((line, index) => {
    const isDescriptionOnly = line.DetailType === 'DescriptionOnly';
    const isAccountBased = line.DetailType === 'AccountBasedExpenseLineDetail';
